-- Tüm sütunları seç
SELECT * FROM users;

-- Belirli sütunlar
SELECT name, email FROM users;

-- Filtreleme
SELECT * FROM users WHERE age >= 18;

-- LIKE ile arama
SELECT * FROM users WHERE name LIKE 'A%';  -- A ile başlayanlar
SELECT * FROM users WHERE email LIKE '%@gmail.com';  -- Gmail kullanıcıları

-- IN operatörü
SELECT * FROM users WHERE city IN ('İstanbul', 'Ankara', 'İzmir');

-- BETWEEN
SELECT * FROM products WHERE price BETWEEN 100 AND 500;

-- Sıralama
SELECT * FROM users ORDER BY created_at DESC;

-- Limit
SELECT * FROM users ORDER BY id DESC LIMIT 10;

-- Index oluşturma
CREATE INDEX idx_users_email ON users(email);

-- Composite index
CREATE INDEX idx_orders_user_date ON orders(user_id, order_date);

-- Unique index
CREATE UNIQUE INDEX idx_users_username ON users(username);

-- Partial index (PostgreSQL)
CREATE INDEX idx_active_users ON users(email) WHERE is_active = true;

-- Full-text index (MySQL)
CREATE FULLTEXT INDEX idx_posts_content ON posts(title, content);

-- Index kullanımını kontrol et
EXPLAIN SELECT * FROM users WHERE email = 'test@example.com';

-- Index listesi
SHOW INDEX FROM users;

-- Index silme
DROP INDEX idx_users_email ON users;

-- Index rebuild (fragmentation sonrası)
ALTER TABLE users ENGINE=InnoDB;

-- Transaction başlat
START TRANSACTION;

-- Para transferi örneği
UPDATE accounts SET balance = balance - 100 WHERE id = 1;
UPDATE accounts SET balance = balance + 100 WHERE id = 2;

-- Başarılıysa kaydet
COMMIT;

-- Hata varsa geri al
ROLLBACK;

-- Savepoint kullanımı
START TRANSACTION;
INSERT INTO orders (user_id, total) VALUES (1, 100);
SAVEPOINT sp1;
INSERT INTO order_items (order_id, product_id) VALUES (1, 5);
ROLLBACK TO sp1;  -- Sadece order_items geri alındı
COMMIT;

-- Isolation level ayarlama
SET TRANSACTION ISOLATION LEVEL READ COMMITTED;

-- Deadlock örneği
-- Transaction 1:
START TRANSACTION;
UPDATE accounts SET balance = balance - 10 WHERE id = 1;
-- Transaction 2 bekliyor...
UPDATE accounts SET balance = balance + 10 WHERE id = 2;
COMMIT;

-- Transaction 2:
START TRANSACTION;
UPDATE accounts SET balance = balance - 10 WHERE id = 2;
UPDATE accounts SET balance = balance + 10 WHERE id = 1;  -- Deadlock!
COMMIT;

// MongoDB bağlantısı (Node.js)
const { MongoClient } = require('mongodb');

const client = new MongoClient('mongodb://localhost:27017');
await client.connect();

const db = client.db('myapp');
const users = db.collection('users');

// Insert
await users.insertOne({
    name: 'Ahmet',
    email: 'ahmet@example.com',
    age: 25,
    tags: ['developer', 'nodejs'],
    address: {
        city: 'İstanbul',
        country: 'Turkey'
    }
});

// Find
const user = await users.findOne({ email: 'ahmet@example.com' });

// Query
const developers = await users.find({
    tags: 'developer',
    age: { $gte: 20 }
}).toArray();

// Update
await users.updateOne(
    { email: 'ahmet@example.com' },
    { $set: { age: 26 }, $push: { tags: 'mongodb' } }
);

// Delete
await users.deleteOne({ email: 'ahmet@example.com' });

// Aggregation
const result = await users.aggregate([
    { $match: { age: { $gte: 18 } } },
    { $group: { _id: '$city', count: { $sum: 1 } } },
    { $sort: { count: -1 } }
]).toArray();

// Redis bağlantısı (Node.js)
const redis = require('redis');
const client = redis.createClient();

await client.connect();

// String operations
await client.set('user:1:name', 'Ahmet');
const name = await client.get('user:1:name');

// Expiration (10 saniye)
await client.setEx('session:abc123', 10, 'user_data');

// Increment
await client.incr('page:views');

// Hash (object)
await client.hSet('user:1', {
    name: 'Ahmet',
    email: 'ahmet@example.com',
    age: '25'
});
const user = await client.hGetAll('user:1');

// List (queue)
await client.lPush('queue:jobs', 'job1');
await client.lPush('queue:jobs', 'job2');
const job = await client.rPop('queue:jobs');

// Set (unique values)
await client.sAdd('tags', 'nodejs');
await client.sAdd('tags', 'redis');
const tags = await client.sMembers('tags');

// Pub/Sub
await client.subscribe('notifications', (message) => {
    console.log('Received:', message);
});

await client.publish('notifications', 'New order!');

// Cache pattern
async function getUser(id) {
    const cached = await client.get(`user:${id}`);
    if (cached) return JSON.parse(cached);

    const user = await db.users.findById(id);
    await client.setEx(`user:${id}`, 3600, JSON.stringify(user));
    return user;
}

// Eventual Consistency örneği

// Write to primary
await primaryDB.users.insertOne({ name: 'Ahmet' });

// Read from replica (hemen sonra)
const user = await replicaDB.users.findOne({ name: 'Ahmet' });
// user null olabilir (henüz replicate olmadı)

// Biraz bekle
await new Promise(resolve => setTimeout(resolve, 100));
const user2 = await replicaDB.users.findOne({ name: 'Ahmet' });
// user2 artık bulunur (eventually consistent)

// Strong Consistency (MongoDB)
const user3 = await db.users.findOne(
    { name: 'Ahmet' },
    { readConcern: { level: 'majority' } }
);
